const items = $input.all();
const output = [];

function pad2(n) {
  return String(n).padStart(2, "0");
}

function excelSerialToIso(serial) {
  const num = Number(serial);
  if (!Number.isFinite(num) || num < 1000) return "";
  const utcDays = Math.floor(num - 25569);
  const date = new Date(utcDays * 86400 * 1000);
  const y = date.getUTCFullYear();
  const m = pad2(date.getUTCMonth() + 1);
  const d = pad2(date.getUTCDate());
  return `${y}-${m}-${d}`;
}

function dateTextToIso(value) {
  if (value === null || value === undefined) return "";
  const str = String(value).trim();
  if (!str) return "";
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(str)) {
    const [mm, dd, yyyy] = str.split("/");
    return `${yyyy}-${mm}-${dd}`;
  }
  const asNum = Number(str);
  if (Number.isFinite(asNum)) return excelSerialToIso(asNum);
  return "";
}

function dateTextToUS(value) {
  if (value === null || value === undefined) return "";
  const str = String(value).trim();
  if (!str) return "";
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(str)) return str;
  const iso = dateTextToIso(str);
  if (!iso) return str;
  const [y, m, d] = iso.split("-");
  return `${m}/${d}/${y}`;
}

function normalizeMxPhone(value) {
  const digits = String(value || "").replace(/[^0-9]/g, "").trim();
  if (!digits) return "";
  if (digits.length === 10) return "521" + digits;
  if (digits.length === 12 && digits.startsWith("52")) return "521" + digits.slice(2);
  if (digits.length === 13 && digits.startsWith("521")) return digits;
  return digits;
}

function pick(row, keys) {
  for (const k of keys) {
    if (row[k] !== undefined && row[k] !== null && String(row[k]).trim() !== "") return row[k];
  }
  return "";
}

for (const item of items) {
  const row = item.json;
  const documento = pick(row, ["DOCUMENTO","Documento","__EMPTY_5"]);
  if (!documento) continue;
  if (String(documento).trim().toUpperCase() === "DOCUMENTO") continue;

  const docNum = parseInt(documento, 10);
  if (Number.isNaN(docNum)) continue;

  const telefono = normalizeMxPhone(pick(row, ["TELEFONO1","TELEFONO","Telefono","__EMPTY_4"]));
  const razonSocial = String(pick(row, ["RAZON SOCIAL","RAZON_SOCIAL","Razon Social","__EMPTY_3"]) || "Desconocido").trim();
  const vendedor = String(pick(row, ["VENDEDOR","__EMPTY"]) || "").trim();
  const codVenRaw = String(pick(row, ["COD VEN","COD_VEN","Cod Ven","__EMPTY_1"]) || "").trim();
  const codVen = codVenRaw.replace(/[^0-9]/g, "");

  const saldoDoc = parseFloat(String(pick(row, ["SALDO DOC","SALDO_DOC","Saldo Doc","__EMPTY_17"]) || "0").replace(/,/g, "")) || 0;
  const montoUsd = parseFloat(String(pick(row, ["MONTO USD","MONTO_USD","Monto USD","__EMPTY_16"]) || "0").replace(/,/g, "")) || 0;
  const pago = parseFloat(String(pick(row, ["PAGO","PAGO_1","Pago","__EMPTY_18"]) || "0").replace(/,/g, "")) || 0;
  const diasVenc = parseInt(String(pick(row, ["DIAS VENCIDOS","DIAS_VENCIDOS","Dias Vencidos","__EMPTY_13"]) || "0"), 10) || 0;

  const fechaVencUS = dateTextToUS(pick(row, ["FECHA VENC","FECHA_VENC","Fecha Venc","__EMPTY_12"]));
  const fechaVencISO = dateTextToIso(pick(row, ["FECHA VENC","FECHA_VENC","Fecha Venc","__EMPTY_12"]));

  output.push({
    json: {
      VENDEDOR: vendedor,
      COD_VEN: codVen,
      DOCUMENTO: String(docNum),
      RAZON_SOCIAL: razonSocial,
      TELEFONO: telefono,
      SALDO_DOC: saldoDoc,
      FECHA_VENC: fechaVencUS,
